def solve(nums: Array[Long], k: Long): Long = {
  if (nums.length == 1) return 0L

  val sorted = nums.sorted
  var minRemove = 0L

  for (i <- 1 until nums.length) {
    val max = sorted(nums.length - 1)
    val min = sorted(i)
    if (max > min * k) {
      minRemove += (nums.length - i)
      return minRemove
    }
  }

  minRemove
}
